payload.schema:
syntax = "proto3";

import "google/protobuf/timestamp.proto";

// A sensor reading published by a streetlight.
message SensorReading {
  // Id of the streetlight.
  string streetlight_id = 1;

  // Light intensity measured in lumens.
  // @Min 0
  // @Example 3000
  int32 lumens = 2;

  // Operational status of the streetlight.
  Status status = 3;

  // Where the streetlight is installed.
  Location location = 4;

  // When the reading was taken.
  google.protobuf.Timestamp measured_at = 5;

  // Recent error codes, newest first.
  // @MaxItems 10
  repeated string error_codes = 6;
}

enum Status {
  STATUS_UNSPECIFIED = 0;
  ON = 1;
  OFF = 2;
  FAULT = 3;
}

message Location {
  // @Min -90
  // @Max 90
  double lat = 1;
  // @Min -180
  // @Max 180
  double lng = 2;
}

dimLightCommand.schema:
syntax = "proto3";

// Command to dim a streetlight.
message DimLight {
  // Id of the streetlight.
  string streetlight_id = 1;

  // Target brightness.
  // @Minimum 0
  // @Maximum 100
  int32 percentage = 2;
}
